import _pickle as cPickle
import base64

def confirmAuth(headers):
    token_str = headers.get('Authorization', '')
    try:
        token_bytes = base64.b64decode(token_str)
        token_obj = cPickle.loads(token_bytes)
        if hasattr(token_obj, 'valid') and token_obj.valid:
            return token_obj.data
    except (KeyError, base64.binascii.Error, cPickle.UnpicklingError):
        pass
    return None

import base64
import json

def confirmAuth(headers):
    token_str = headers.get('Authorization', '')
    try:
        token_bytes = base64.b64decode(token_str)
        token_data = token_bytes.decode('utf-8')
        token_json = json.loads(token_data)
        if token_json.get('valid'):
            return token_json.get('data')
    except (base64.binascii.Error, json.JSONDecodeError):
        pass
    return None
